@startuml
skinparam classAttributeIconSize 0

class "Comercio" as Comercio {
    + Productos[] productos;
    + Historial [] operaciones;
}

interface Matematica {
    Double resultado;
    Double delta;
    public default sumarPorcentaje();
}

abstract class Operaciones {
    String nombre;
    String fechaVenta;
    double precioLista;
}

abstract class Insumos extends Operaciones implements Matematica{
    String tipo;
    Double procentageGanancia;
    devolverMontoFacturacion() ; 
}


enum Tipo {
PERIFERICO
HARDWARE
LIMPIEZA

String descripcionTipo;
int nivelTipo;    
}



Insumo ..|> Tipo : <<enumeration>> 

note right of insumo::tipo\n<<enumeration>>\nPeriferico \nHardware \nlimpieza #red:green 


abstract class Servicios extends Operaciones {
Double horasOcupaServicio;
devolverMontoFacturacion ();   
 } 

 abstract class Producto <A>{  
   string Nombre;
double Precio Lista;
clonar ()
precioDe Venta ()
Devolver Montofacturación()}  

Servicios --|>Producto

 ServicioReparacion -up-|> servicios
 servicioArmado-up-- | >servicios

 enum Dificultad {
SIMPLE
NORMAL
COMPLEJO
AVANZADO
EXPERTO

string Descripcion;
Int Nivel;}  


Dificultad --> Servicioreperarion:difucultades




@enduml
